package com.glintsmp.emotion.Emotions.Ability.Abilities;

import com.glintsmp.emotion.Emotions.Ability.Ability;
import com.glintsmp.emotion.Emotions.Emotion;
import org.bukkit.Particle;
import org.bukkit.Sound;
import org.bukkit.entity.Player;
import org.bukkit.location.Location;

public class ElectroStorm implements Ability {
    @Override
    public boolean activate(Player player, Emotion emotion) {
        boolean did = false;
        for (Player target : player.getLocation().getNearbyPlayers(12)) {
            Location loc = target.getLocation().add(0, 1, 0);
            // non-damaging lightning visuals
            target.getWorld().strikeLightningEffect(loc);
            target.getWorld().spawnParticle(Particle.ELECTRIC_SPARK, loc, 20, 0.5, 0.5, 0.5, 0.02);
            target.getWorld().playSound(loc, Sound.ENTITY_LIGHTNING_BOLT_THUNDER, 1.0f, 1.0f);

            // small damage to emphasize impact
            target.damage(3.0, player);
            did = true;
        }
        return did;
    }
}

package com.glintsmp.emotion.Emotions.Ability.Abilities;

import com.glintsmp.emotion.Emotions.Ability.Ability;
import com.glintsmp.emotion.Emotions.Emotion;
import org.bukkit.Particle;
import org.bukkit.Sound;
import org.bukkit.entity.Player;
import org.bukkit.util.Vector;

public class GravityWell implements Ability {
    @Override
    public boolean activate(Player player, Emotion emotion) {
        boolean pulled = false;
        Vector center = player.getLocation().toVector();

        for (Player p : player.getLocation().getNearbyPlayers(8)) {
            if (p.equals(player)) continue;
            Vector dir = center.subtract(p.getLocation().toVector()).normalize().multiply(0.7);
            // keep some upward component so players don't clip badly
            dir.setY(Math.max(dir.getY(), 0.15));
            p.setVelocity(dir);
            p.getWorld().spawnParticle(Particle.PORTAL, p.getLocation().add(0,0.5,0), 8, 0.3, 0.3, 0.3, 0.01);
            p.getWorld().playSound(p.getLocation(), Sound.ENTITY_ENDERMAN_TELEPORT, 0.6f, 1.2f);
            pulled = true;
        }

        return pulled;
    }
}

package com.glintsmp.emotion.Emotions.Ability.Abilities;

import com.glintsmp.emotion.Emotions.Ability.Ability;
import com.glintsmp.emotion.Emotions.Emotion;
import org.bukkit.Particle;
import org.bukkit.entity.Player;

public class LifeSteal implements Ability {
    @Override
    public boolean activate(Player player, Emotion emotion) {
        boolean used = false;
        double healTotal = 0.0;

        for (Player target : player.getLocation().getNearbyPlayers(6)) {
            if (target.equals(player)) continue;
            double dmg = 2.5;
            target.damage(dmg, player);
            healTotal += dmg * 0.6; // 60% of damage becomes heal
            target.getWorld().spawnParticle(Particle.DAMAGE_INDICATOR, target.getLocation().add(0,1,0), 6, 0.2, 0.2, 0.2, 0.01);
            used = true;
        }

        if (used && healTotal > 0) {
            double newHealth = Math.min(player.getMaxHealth(), player.getHealth() + healTotal);
            player.setHealth(newHealth);
            player.getWorld().spawnParticle(Particle.HEART, player.getLocation().add(0,1,0), 8);
        }

        return used;
    }
}
